module top_module(
    input clk,
    input set,
    input enable,
    input [11:0] d,
    output reg [11:0] q);  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge set or posedge dbg_halt) begin
    if (set)
        q <= 12'b111111111111;
    else if (enable)
        q <= d;
end
endmodule
